const contactForm=document.querySelector("#contact-form"),errbox=document.querySelector(".errbox"),validate=fields=>{const errors=[];if(errbox.innerHTML="",errbox.classList.remove("show"),stringLength(fields.firstName.value.trim())<2&&errors.push("Please enter your first name."),stringLength(fields.lastName.value.trim())<2&&errors.push("Please enter your last name."),!/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(fields.email.value.trim())&&errors.push("Please enter a valid email address."),stringLength(fields.phone.value)&&!/^\([0-9]{3}\) [0-9]{3}\-[0-9]{4}$/.test(fields.phone.value)&&errors.push("Please check the phone number you entered."),stringLength(fields.message.value.trim())<10&&errors.push("Please enter a longer message."),errors.length){for(let error of errors)errbox.insertAdjacentHTML("beforeend",`<li><img src="/public/icons/error_circle_icon.svg" alt="error icon" /><span>${error}</span></li>`);errbox.classList.add("show")}return!errors.length},submitForm=evt=>{evt.preventDefault();const fields={firstName:document.querySelector("#first-name"),lastName:document.querySelector("#last-name"),email:document.querySelector("#email"),phone:document.querySelector("#phone"),canText:document.querySelector("#can-text"),message:document.querySelector("#message")};validate(fields)&&alert("success!")};contactForm.addEventListener("submit",submitForm);